/* ডিফল্ট: মোবাইল-প্রথম স্টাইল */
.container {
  display: flex;
  flex-direction: column;
}

/* ট্যাবলেট ও তার বড় স্ক্রিনে */
@media (min-width: 768px) {
  .container {
    flex-direction: row;
  }
}

/* ডেস্কটপ */
@media (min-width: 1200px) {
  .container {
    max-width: 1140px;
    margin: 0 auto;
  }
}
